class MinHeap:
    def __init__(self):
        self._heap = []

    def _get_parent_idx(self, i):
        return (i - 1) // 2

    def _get_left_child_idx(self, i):
        return 2 * i + 1

    def _get_right_child_idx(self, i):
        return 2 * i + 2

    def _has_parent(self, i):
        return self._get_parent_idx(i) >= 0

    def _has_left_child(self, i):
        return self._get_left_child_idx(i) < self.size()

    def _has_right_child(self, i):
        return self._get_right_child_idx(i) < self.size()

    def _get_parent(self, i):
        return self._heap[self._get_parent_idx(i)]

    def _get_left_child(self, i):
        return self._heap[self._get_left_child_idx(i)]

    def _get_right_child(self, i):
        return self._heap[self._get_right_child_idx(i)]

    def _swap(self, i, j):
        self._heap[i], self._heap[j] = self._heap[j], self._heap[i]

    def size(self):
        return len(self._heap)

    def is_empty(self):
        return self.size() == 0

    def peek(self):
        if self.is_empty():
            raise IndexError("Heap is empty")
        return self._heap[0]

    def add(self, item):
        self._heap.append(item)
        self._heapify_up()

    def poll(self):
        if self.is_empty():
            raise IndexError("Heap is empty")

        item = self._heap[0]
        self._heap[0] = self._heap[-1]
        self._heap.pop()
        self._heapify_down()
        return item

    def _heapify_up(self):
        current_idx = self.size() - 1
        while self._has_parent(current_idx) and self._heap[current_idx] < self._get_parent(current_idx):
            self._swap(current_idx, self._get_parent_idx(current_idx))
            current_idx = self._get_parent_idx(current_idx)

    def _heapify_down(self):
        current_idx = 0
        while self._has_left_child(current_idx):
            smaller_child_idx = self._get_left_child_idx(current_idx)
            if self._has_right_child(current_idx) and self._get_right_child(current_idx) < self._get_left_child(current_idx):
                smaller_child_idx = self._get_right_child_idx(current_idx)

            if self._heap[current_idx] < self._heap[smaller_child_idx]:
                break
            else:
                self._swap(current_idx, smaller_child_idx)
            current_idx = smaller_child_idx
